typedef struct {
    int id;
    char name[20];
} Record;

int main(void) {
    /* Create a binary file with records */
    FILE *fp = fopen("records.bin", "w+b");
    if (!fp) { perror("fopen"); return 1; }

    Record records[] = {
        {1, "Alice"}, {2, "Bob"}, {3, "Charlie"}, {4, "Diana"}
    };
    fwrite(records, sizeof(Record), 4, fp);

    /* Get file size using fseek + ftell */
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    printf("File size: %ld bytes\n", file_size);
    printf("Records: %ld\n", file_size / (long)sizeof(Record));

    /* Random access: read record #2 (index 2) directly */
    fseek(fp, 2 * sizeof(Record), SEEK_SET);
    Record r;
    fread(&r, sizeof(Record), 1, fp);
    printf("Record 2: id=%d name=%s\n", r.id, r.name); /* Charlie */

    /* Read record #0 */
    rewind(fp); /* same as fseek(fp, 0, SEEK_SET) + clear error */
    fread(&r, sizeof(Record), 1, fp);
    printf("Record 0: id=%d name=%s\n", r.id, r.name); /* Alice */

    /* Move relative to current position */
    fseek(fp, sizeof(Record), SEEK_CUR); /* skip one record */
    long pos = ftell(fp);
    printf("Current position: %ld (record index %ld)\n",
           pos, pos / (long)sizeof(Record)); /* record 2 */

    /* Update a specific record in place */
    Record updated = {2, "Robert"};
    fseek(fp, 1 * sizeof(Record), SEEK_SET);
    fwrite(&updated, sizeof(Record), 1, fp);

    /* Verify update */
    fseek(fp, 1 * sizeof(Record), SEEK_SET);
    fread(&r, sizeof(Record), 1, fp);
    printf("Updated record 1: id=%d name=%s\n", r.id, r.name); /* Robert */

    fclose(fp);
    remove("records.bin");
    return 0;
}

