#include <stdio.h>

int main(void) {
    /* Create test file */
    FILE *fp = fopen("nums.txt", "w");
    fprintf(fp, "10 20 30");
    fclose(fp);

    /* WRONG: while (!feof(fp)) -- processes last value twice */
    printf("WRONG approach:\n");
    fp = fopen("nums.txt", "r");
    int val;
    while (!feof(fp)) {
        fscanf(fp, "%d", &val);
        printf("  read: %d\n", val);
    }
    fclose(fp);
    /* Output: 10, 20, 30, 30 (30 appears twice!) */

    /* CORRECT: check fscanf return value */
    printf("CORRECT approach:\n");
    fp = fopen("nums.txt", "r");
    while (fscanf(fp, "%d", &val) == 1) {
        printf("  read: %d\n", val);
    }
    /* Distinguish EOF from error */
    if (feof(fp)) {
        printf("  (reached end of file)\n");
    } else if (ferror(fp)) {
        printf("  (read error occurred)\n");
    }
    fclose(fp);
    /* Output: 10, 20, 30 (correct!) */

    /* CORRECT: fgets pattern */
    printf("fgets approach:\n");
    fp = fopen("nums.txt", "r");
    char buf[100];
    while (fgets(buf, sizeof(buf), fp) != NULL) {
        printf("  line: [%s]\n", buf);
    }
    fclose(fp);

    remove("nums.txt");
    return 0;
}

