#include <stdio.h>
#include <string.h>

int main(void) {
    /* Create a temporary file */
    FILE *tmp = tmpfile();
    if (!tmp) {
        perror("tmpfile");
        return 1;
    }

    /* Write data to temporary file */
    const char *data = "Temporary data for processing";
    fwrite(data, 1, strlen(data), tmp);
    printf("Wrote %zu bytes to temp file\n", strlen(data));

    /* Seek back to beginning and read */
    rewind(tmp);
    char buf[100] = {0};
    size_t nread = fread(buf, 1, sizeof(buf) - 1, tmp);
    printf("Read back: [%s] (%zu bytes)\n", buf, nread);

    /* Use as scratch space for sorting or processing */
    int numbers[] = {50, 10, 40, 20, 30};
    rewind(tmp);
    fwrite(numbers, sizeof(int), 5, tmp);

    rewind(tmp);
    int sorted[5];
    fread(sorted, sizeof(int), 5, tmp);
    printf("Numbers: %d %d %d %d %d\n",
           sorted[0], sorted[1], sorted[2], sorted[3], sorted[4]);

    /* File is automatically deleted when closed */
    fclose(tmp);
    printf("Temp file automatically cleaned up\n");

    /* AVOID: tmpnam is insecure (TOCTOU race) */
    /* char *name = tmpnam(NULL); -- DEPRECATED */

    return 0;
}

