int main(void) {
    /* Attempt to open nonexistent file */
    FILE *fp = fopen("nonexistent.txt", "r");
    if (!fp) {
        /* Method 1: perror -- prints to stderr */
        perror("fopen nonexistent.txt");
        /* Output: fopen nonexistent.txt: No such file or directory */

        /* Method 2: strerror -- for custom messages */
        fprintf(stderr, "Error %d: %s\n", errno, strerror(errno));

        /* Method 3: check specific errno values */
        if (errno == ENOENT) {
            printf("File does not exist\n");
        } else if (errno == EACCES) {
            printf("Permission denied\n");
        }
    }

    /* Write to read-only location (if possible) */
    fp = fopen("/dev/null", "r"); /* read-only */
    if (fp) {
        int result = fputc('x', fp); /* write to read-only stream */
        if (result == EOF) {
            printf("fputc failed\n");
        }
        if (ferror(fp)) {
            printf("Stream error flag is set\n");
            clearerr(fp); /* reset error and EOF flags */
            printf("After clearerr: ferror=%d\n", ferror(fp)); /* 0 */
        }
        fclose(fp);
    }

    /* Proper error handling pattern */
    const char *path = "output.txt";
    fp = fopen(path, "w");
    if (!fp) {
        perror(path);
        return 1;
    }
    if (fprintf(fp, "data\n") < 0) {
        perror("fprintf");
        fclose(fp);
        return 1;
    }
    if (fclose(fp) != 0) {
        perror("fclose"); /* disk full detected at flush */
        return 1;
    }

    remove("output.txt");
    printf("All error handling demonstrated\n");
    return 0;
}

