    /* stderr is unbuffered by default */
    fprintf(stderr, "This appears immediately\n");

    /* stdout may be line-buffered (terminal) or fully buffered (pipe) */
    /* Force stdout to be unbuffered: */
    /* setvbuf(stdout, NULL, _IONBF, 0); */

    /* Demonstrate: stdout buffering affects output order */
    printf("stdout (may be buffered)");
    fprintf(stderr, "stderr (always immediate)\n");
    printf("\n"); /* \n may flush stdout if line-buffered */

    remove("full_buf.txt");
    remove("line_buf.txt");
    remove("unbuf.txt");
    return 0;
}

