#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char name[50];
    int age;
    double gpa;
} Student;

/* Method 1: Parse CSV with strtok */
int parse_csv_strtok(const char *filename, Student *out, int max) {
    FILE *fp = fopen(filename, "r");
    if (!fp) { perror(filename); return -1; }

    char line[256];
    fgets(line, sizeof(line), fp); /* skip header */

    int count = 0;
    while (count < max && fgets(line, sizeof(line), fp)) {
        line[strcspn(line, "\n")] = '\0'; /* strip newline */

        char *name = strtok(line, ",");
        char *age_str = strtok(NULL, ",");
        char *gpa_str = strtok(NULL, ",");

        if (name && age_str && gpa_str) {
            strncpy(out[count].name, name, sizeof(out[count].name) - 1);
            out[count].name[sizeof(out[count].name) - 1] = '\0';
            out[count].age = atoi(age_str);
            out[count].gpa = atof(gpa_str);
            count++;
        }
    }
    fclose(fp);
    return count;
}

/* Method 2: Parse with sscanf (fixed format) */
int parse_csv_sscanf(const char *filename, Student *out, int max) {
    FILE *fp = fopen(filename, "r");
    if (!fp) return -1;

    char line[256];
    fgets(line, sizeof(line), fp); /* skip header */

    int count = 0;
    while (count < max && fgets(line, sizeof(line), fp)) {
        if (sscanf(line, "%49[^,],%d,%lf",
                   out[count].name, &out[count].age,
                   &out[count].gpa) == 3) {
            count++;
        }
    }
    fclose(fp);
    return count;
}

int main(void) {
    /* Create test CSV */
    FILE *fp = fopen("students.csv", "w");
    fprintf(fp, "name,age,gpa\n");
    fprintf(fp, "Alice,20,3.80\n");
    fprintf(fp, "Bob,22,3.50\n");
    fprintf(fp, "Charlie,21,3.95\n");
    fclose(fp);

    /* Parse with strtok */
    Student students[10];
    int n = parse_csv_strtok("students.csv", students, 10);
    printf("Parsed %d students (strtok):\n", n);
    for (int i = 0; i < n; i++) {
        printf("  %s, age %d, GPA %.2f\n",
               students[i].name, students[i].age, students[i].gpa);
    }

    /* Parse with sscanf */
    n = parse_csv_sscanf("students.csv", students, 10);
    printf("Parsed %d students (sscanf):\n", n);
    for (int i = 0; i < n; i++) {
        printf("  %s, age %d, GPA %.2f\n",
               students[i].name, students[i].age, students[i].gpa);
    }

    remove("students.csv");
    return 0;
}

